import SwiftData

@Model class PersonV1 {
    var name: String
    init(name: String) { self.name = name }
}

@Model class PersonV2 {
    var firstName: String
    var lastName: String
    init(firstName: String, lastName: String) {
        self.firstName = firstName
        self.lastName = lastName
    }
}

struct V1: VersionedSchema {
    static var versionIdentifier: Schema.Version = .init(1,0,0)
    static var models: [any PersistentModel.Type] { [PersonV1.self] }
}
struct V2: VersionedSchema {
    static var versionIdentifier: Schema.Version = .init(2,0,0)
    static var models: [any PersistentModel.Type] { [PersonV2.self] }
}

let migrator = ModelMigrator(
    from: V1.self,
    to: V2.self,
    migrationPolicy: .custom { old, new in
        if let old = old as? PersonV1, let new = new as? PersonV2 {
            let parts = old.name.split(separator: " ", maxSplits: 1)
            new.firstName = String(parts.first ?? "")
            new.lastName = String(parts.dropFirst().first ?? "")
        }
    }
)

import SwiftData

enum Priority: Int, Codable { case low, medium, high, critical }
@Model class Task {
    var dueDate: Date
    var completed: Bool
    var priority: Priority
}

let nextWeek = Calendar.current.date(byAdding: .day, value: 7, to: .now)!
let predicate = #Predicate<Task> { task in
    task.dueDate >= .now &&
    task.dueDate <= nextWeek &&
    !task.completed &&
    (task.priority == .high || task.priority == .critical)
}

