import SwiftData

@Model class Contact {
    var name: String
    var addressID: UUID
}
@Model class Address {
    var id: UUID
    var street: String
    var city: String
}
@Model class ContactV2 {
    var name: String
    var street: String
    var city: String
}

struct V1: VersionedSchema {
    static var versionIdentifier: Schema.Version = .init(1,0,0)
    static var models: [any PersistentModel.Type] { [Contact.self, Address.self] }
}
struct V2: VersionedSchema {
    static var versionIdentifier: Schema.Version = .init(2,0,0)
    static var models: [any PersistentModel.Type] { [ContactV2.self] }
}

let migrator = ModelMigrator(
    from: V1.self,
    to: V2.self,
    migrationPolicy: .custom { old, new, context in
        if let oldContact = old as? Contact, let newContact = new as? ContactV2 {
            newContact.name = oldContact.name
            if let address = context.fetch(Address.self, id: oldContact.addressID) {
                newContact.street = address.street
                newContact.city = address.city
            }
        }
    }
)

